import React from 'react'
import { Link } from 'wouter'

import './listicons.css'

const SIZE = ['small', 'medium', 'high']

export default function ListIcons({ size = SIZE[1] }) {
    const setSize = size => {
        if(size === SIZE[0]) return 'list-icons__small'
        if(size === SIZE[1]) return ''
        if(size === SIZE[2]) return 'list-icons__high'
    }

    return (
        <ul className={`list-icons ${setSize(size)}`}>
            <li className="list-icons__circle">
                <Link to="/alumno"
                ><i className="fab fa-instagram list-icons__icon"></i></Link>
            </li>
            <li className="list-icons__circle">
                <Link to="/profesor"
                ><i className="fab fa-facebook list-icons__icon"></i></Link>
            </li>
            <li className="list-icons__circle">
                <Link to="/administrador"
                ><i className="fab fa-twitter list-icons__icon"></i></Link>
            </li>
            <li className="list-icons__circle">
                <Link to="/administrador"
                ><i className="fab fa-youtube list-icons__icon"></i></Link>
            </li>
        </ul>
    )
}
