import React from 'react'
import { Link } from 'wouter'

import './button.css'

export function ButtonOutlineLight() {
    return (
        <Link to="" className="button button__outline-light">
            Explore all <i class="fas fa-arrow-right button__icon"></i>
        </Link>
    )
}

export function ButtonPurple() {
    return <Link to="" className="button button__purple">Nosotros</Link>
}

